  if |restrictions| == 0 then h
  else
    var prev := EffectiveCap(i, h, restrictions[..|restrictions|-1]);
    var r := restrictions[|restrictions|-1];
    if r.0 - 1 <= i < r.1 && r.2 < prev then r.2
