ghost predicate IsValidAssignment(a: seq<int>, n: int, h: int, restrictions: seq<(int, int, int)>)
  requires n >= 0
{
  |a| == n &&
  (forall i | 0 <= i < n :: 0 <= a[i] <= h) &&
  (forall k | 0 <= k < |restrictions| ::
    forall j | restrictions[k].0 - 1 <= j < restrictions[k].1 ::
